      const errorText = await response.text();
      throw new Error(`HTTP error! Status: ${response.status}, Message: ${errorText}`);
    }
    const result = await response.json();
    return result;
  } catch (error) {
    console.error("Error in GET request:", error.message);
    throw error;
  }
};

